<template>
    <div class="register-wrapper">
      <div class="register-card">
        <h2><span class="icon">📝</span>立即註冊</h2>
        <form @submit.prevent="register" class="register-form">
          <input v-model="username" placeholder="👤 使用者名稱" required />
          <input v-model="password" type="password" placeholder="🔒 密碼" required />
          <input v-model="email" type="email" placeholder="📧 電子信箱" required />
          <button type="submit">註冊</button>
          <p v-if="error" class="error">{{ error }}</p>
          <p v-if="success" class="success">{{ success }}</p>
        </form>
        <p class="login-link">
          已有帳號？<a @click="goToLogin">立即登入</a>
        </p>
      </div>
    </div>
  </template>
   
  <script>
  import axios from 'axios';
   
  export default {
    name: "RegisterPage",
    data() {
      return {
        username: "",
        password: "",
        email: "",
        error: "",
        success: "",
        loading: false
      };
    },
    methods: {
      async register() {
        this.loading = true;
        try {
          await axios.post("http://localhost:8080/api/register", {
            username: this.username,
            password: this.password,
            email: this.email
          });
          this.success = "🎉 註冊成功，即將導向登入畫面";
          this.error = "";
          setTimeout(() => {
            this.$router.push("/login");
          }, 1500);
        } catch (err) {
          this.error = "⚠️ 註冊失敗，帳號或信箱可能已存在。";
          this.success = "";
        } finally {
          this.loading = false;
        }
      },
      goToLogin() {
        this.$router.push("/login");
      }
    }
  };
  </script>
   
